#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Rick Roll ASCII Art - Professional Edition
Never Gonna Give You Up
"""

import os
import sys
import time
import random

# ANSI Color Codes
class Colors:
    RED = '\033[91m'
    GREEN = '\033[92m'
    YELLOW = '\033[93m'
    BLUE = '\033[94m'
    MAGENTA = '\033[95m'
    CYAN = '\033[96m'
    WHITE = '\033[97m'
    BOLD = '\033[1m'
    UNDERLINE = '\033[4m'
    RESET = '\033[0m'
    
    # Background colors
    BG_RED = '\033[101m'
    BG_GREEN = '\033[102m'
    BG_YELLOW = '\033[103m'
    BG_BLUE = '\033[104m'
    BG_MAGENTA = '\033[105m'
    BG_CYAN = '\033[106m'

def clear_screen():
    """Clear the terminal screen"""
    os.system('cls' if os.name == 'nt' else 'clear')

def print_slow(text, delay=0.03, color=Colors.WHITE):
    """Print text with typing effect"""
    print(color, end='')
    for char in text:
        sys.stdout.write(char)
        sys.stdout.flush()
        time.sleep(delay)
    print(Colors.RESET)

def print_centered(text, width=70, color=Colors.WHITE):
    """Print text centered in a given width"""
    padding = (width - len(text)) // 2
    print(f"{' ' * padding}{color}{text}{Colors.RESET}")

def animate_text(text, delay=0.05, color=Colors.YELLOW):
    """Animate text appearing character by character"""
    for char in text:
        sys.stdout.write(f"{color}{char}{Colors.RESET}")
        sys.stdout.flush()
        time.sleep(delay)
    print()

